mapper.update:
UPDATE tbl_message
SET is_read = true
WHERE message_room_id = #{roomId}
  AND sender_id != #{memberId}
  AND is_read = false
  AND deleted_datetime IS NULL

mapper.select:
SELECT EXISTS(
    SELECT 1
    FROM tbl_message_like
    WHERE member_id = #{memberId}
      AND message_id = #{messageId}
)

mapper.insert:
INSERT INTO tbl_message_like (
    member_id,
    message_id
) VALUES (
    #{memberId},
    #{messageId}
)

mapper.delete:
DELETE FROM tbl_message_like
WHERE member_id = #{memberId}
  AND message_id = #{messageId}
